import type { DiscoveryApi, FetchApi } from '@backstage/core-plugin-api';
import type {
  ChatMessage,
  StreamingEvent,
  StreamingEventCallback,
} from '../types';
import { parseSSEStream } from './sseStreaming';
import { jsonBody } from './fetchHelpers';
import { isAbortError } from '../utils';

export interface ChatApiDeps {
  fetchJson: <T>(path: string, init?: RequestInit) => Promise<T>;
  discoveryApi: DiscoveryApi;
  fetchApi: FetchApi;
}

/**
 * Internal SSE streaming helper shared by chatStream and chatStreamWithSession.
 * Handles timeout, fetch, SSE line parsing, event forwarding, and retry with backoff.
 */
async function streamSSE(
  deps: ChatApiDeps,
  body: Record<string, unknown>,
  onEvent: StreamingEventCallback,
  signal?: AbortSignal,
): Promise<void> {
  const MAX_RETRIES = 3;
  const BASE_DELAY_MS = 1000;
  const baseUrl = await deps.discoveryApi.getBaseUrl('augment');

  let lastError: Error | undefined;
  let receivedContent = false;

  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    if (signal?.aborted) return;

    if (attempt > 0) {
      if (receivedContent) {
        throw lastError || new Error('Stream failed after partial content');
      }
      onEvent({
        type: 'stream.error',
        error: `Reconnecting... (attempt ${attempt}/${MAX_RETRIES})`,
        code: 'reconnecting',
      } as StreamingEvent);
      const delay = BASE_DELAY_MS * Math.pow(2, attempt - 1);
      await new Promise<void>((resolve, reject) => {
        const timer = setTimeout(resolve, delay);
        if (signal) {
          const onAbort = () => {
            clearTimeout(timer);
            reject(signal.reason ?? new DOMException('Aborted', 'AbortError'));
          };
          if (signal.aborted) {
            clearTimeout(timer);
            reject(signal.reason ?? new DOMException('Aborted', 'AbortError'));
            return;
          }
          signal.addEventListener('abort', onAbort, { once: true });
        }
      });
      if (signal?.aborted) return;
    }

    try {
      // eslint-disable-next-line no-loop-func
      const wrappedOnEvent: StreamingEventCallback = evt => {
        const t = (evt as { type?: string }).type;
        if (
          t === 'stream.text.delta' ||
          t === 'stream.completed' ||
          t === 'stream.tool.completed'
        ) {
          receivedContent = true;
        }
        onEvent(evt);
      };
      await streamSSEAttempt(deps, baseUrl, body, wrappedOnEvent, signal);
      return;
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));

      if (signal?.aborted) return;
      if (isAbortError(err)) throw err;

      const isRetryable =
        err instanceof TypeError ||
        (lastError.message.includes('timeout') &&
          !lastError.message.includes('5 minutes')) ||
        lastError.message.includes('Stream request failed: 5');

      if (!isRetryable || attempt === MAX_RETRIES) {
        throw lastError;
      }
    }
  }

  throw lastError || new Error('Stream failed after retries');
}

/**
 * Single SSE connection attempt — extracted from streamSSE for retry logic.
 */
async function streamSSEAttempt(
  deps: ChatApiDeps,
  baseUrl: string,
  body: Record<string, unknown>,
  onEvent: StreamingEventCallback,
  signal?: AbortSignal,
): Promise<void> {
  const STREAM_CONNECT_TIMEOUT_MS = 300_000;
  const timeoutController = new AbortController();
  const timeoutId = setTimeout(() => {
    timeoutController.abort();
  }, STREAM_CONNECT_TIMEOUT_MS);

  const onAbort = () => {
    clearTimeout(timeoutId);
    timeoutController.abort();
  };

  if (signal) {
    signal.addEventListener('abort', onAbort);
  }

  let response: Response;
  try {
    response = await deps.fetchApi.fetch(`${baseUrl}/chat/stream`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      signal: timeoutController.signal,
    });
    clearTimeout(timeoutId);
  } catch (err) {
    clearTimeout(timeoutId);
    signal?.removeEventListener('abort', onAbort);
    if (timeoutController.signal.aborted && !signal?.aborted) {
      throw new Error(
        'Connection timeout: Server did not respond within 5 minutes. The request may have been too complex.',
      );
    }
    throw err;
  }

  if (!response.ok) {
    signal?.removeEventListener('abort', onAbort);
    let detail = '';
    try {
      const rawBody = await response.text();
      try {
        const parsed = JSON.parse(rawBody);
        detail =
          parsed.error?.message || parsed.message || parsed.error || rawBody;
      } catch {
        if (rawBody.length > 0) {
          detail = rawBody.slice(0, 200);
        }
      }
    } catch {
      // Couldn't read body at all
    }
    throw new Error(
      detail
        ? `Stream request failed: ${response.status} — ${detail}`
        : `Stream request failed: ${response.status}`,
    );
  }

  if (!response.body) {
    signal?.removeEventListener('abort', onAbort);
    throw new Error('No response body for streaming');
  }

  const reader = response.body.getReader();
  try {
    await parseSSEStream(reader, onEvent, signal);
  } finally {
    signal?.removeEventListener('abort', onAbort);
  }
}

/**
 * Streaming chat request.
 */
export async function chatStream(
  deps: ChatApiDeps,
  messages: ChatMessage[],
  onEvent: StreamingEventCallback,
  enableRAG: boolean,
  signal?: AbortSignal,
  previousResponseId?: string,
  conversationId?: string,
  model?: string,
): Promise<void> {
  return streamSSE(
    deps,
    { messages, enableRAG, previousResponseId, conversationId, model },
    onEvent,
    signal,
  );
}

/**
 * Streaming chat with session ID.
 */
export async function chatStreamWithSession(
  deps: ChatApiDeps,
  messages: ChatMessage[],
  onEvent: StreamingEventCallback,
  sessionId: string,
  enableRAG: boolean,
  signal?: AbortSignal,
  model?: string,
): Promise<void> {
  return streamSSE(
    deps,
    { messages, enableRAG, sessionId, model },
    onEvent,
    signal,
  );
}

/**
 * Submit tool approval (continue after approval).
 */
export async function submitToolApproval(
  deps: ChatApiDeps,
  responseId: string,
  callId: string,
  approved: boolean,
  toolName?: string,
  toolArguments?: string,
  signal?: AbortSignal,
  reason?: string,
): Promise<{
  success: boolean;
  content?: string;
  responseId?: string;
  rejected?: boolean;
  toolOutput?: string;
  toolExecuted?: boolean;
  outputTruncated?: boolean;
  pendingApproval?: {
    approvalRequestId: string;
    toolName: string;
    serverLabel?: string;
    arguments?: string;
  };
  handoff?: {
    fromAgent: string;
    toAgent: string;
  };
}> {
  return deps.fetchJson(
    '/chat/approve',
    jsonBody(
      { responseId, callId, approved, toolName, toolArguments, reason },
      'POST',
      { signal },
    ),
  );
}
